package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat updatedFormat = csvFormat.withTrailingDelimiter();

        // Then
        assertTrue(updatedFormat.getTrailingDelimiter());
    }

    @Test
    public void testNewFormat() {
        // Given
        char delimiter = ',';

        // When
        CSVFormat csvFormat = CSVFormat.newFormat(delimiter);

        // Then
        assertEquals(delimiter, csvFormat.getDelimiter());
    }

    @Test
    public void testValueOf() {
        // Given
        String format = "CSV";

        // When
        CSVFormat csvFormat = CSVFormat.valueOf(format);

        // Then
        assertNotNull(csvFormat);
    }

    @Test
    public void testAdditionalFunctionality() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat updatedFormat = csvFormat.withAllowMissingColumnNames();

        // Then
        assertTrue(updatedFormat.getAllowMissingColumnNames());
    }

}
